"""Lockfile data model and YAML I/O for pinned action references.

The lockfile maps ``uses:`` strings (as written in user code) to resolved
commit SHAs.  Format::

    # Auto-generated by `ghagen pin`. Do not edit manually.

    pins:
      actions/checkout@v4:
        sha: 3df4ab11eba7bda6032a0b82a6bb43b11571feac
        resolved_at: "2026-04-09T14:30:00+00:00"

A :class:`Lockfile` always holds valid entries: :func:`read_lockfile`
validates every on-disk entry and raises :class:`LockfileError` on malformed
input, and the pins map is private so callers cannot smuggle in invalid state.
"""

from __future__ import annotations

from collections.abc import Iterator, KeysView, Mapping
from dataclasses import dataclass
from datetime import UTC, datetime
from pathlib import Path

from ruamel.yaml import YAML
from ruamel.yaml.scalarstring import DoubleQuotedScalarString

#: Default lockfile path relative to ``App.root``.
DEFAULT_LOCKFILE_PATH = Path(".ghagen.lock.yml")

_HEADER = "# Auto-generated by `ghagen pin`. Do not edit manually.\n\n"


class LockfileError(Exception):
    """Raised when a lockfile on disk is malformed."""


@dataclass(frozen=True)
class PinEntry:
    """A single resolved pin entry."""

    sha: str
    """40-character commit SHA."""

    resolved_at: datetime
    """UTC timestamp of when this entry was resolved."""


class Lockfile:
    """In-memory representation of a ``.ghagen.lock.yml`` file.

    The entry map is private: mutate it through :meth:`set`, :meth:`merge`,
    and :meth:`prune`, and read it through :meth:`get`, iteration, and
    membership tests. This keeps the invariant that a lockfile only ever
    holds valid entries.
    """

    def __init__(self, pins: Mapping[str, PinEntry] | None = None) -> None:
        self._pins: dict[str, PinEntry] = dict(pins) if pins else {}

    def get(self, uses: str) -> PinEntry | None:
        """Look up a pin entry by the full ``uses:`` string."""
        return self._pins.get(uses)

    def set(self, uses: str, entry: PinEntry) -> None:
        """Add or replace a single entry."""
        self._pins[uses] = entry

    def merge(self, entries: Mapping[str, PinEntry]) -> None:
        """Bulk add or replace entries, overwriting existing keys."""
        self._pins.update(entries)

    def prune(self, keep: set[str]) -> int:
        """Remove entries not in *keep*. Return count of removed entries."""
        to_remove = set(self._pins) - keep
        for key in to_remove:
            del self._pins[key]
        return len(to_remove)

    def contains(self, uses: str) -> bool:
        """Return whether *uses* has an entry."""
        return uses in self._pins

    def __contains__(self, uses: object) -> bool:
        return uses in self._pins

    def keys(self) -> KeysView[str]:
        """Return a view over the ``uses:`` keys."""
        return self._pins.keys()

    def __iter__(self) -> Iterator[str]:
        return iter(self._pins)

    def __len__(self) -> int:
        return len(self._pins)


def read_lockfile(path: Path) -> Lockfile:
    """Read a lockfile from disk, validating every entry.

    Returns an empty ``Lockfile`` if the file is missing or empty. Raises
    :class:`LockfileError` (naming the path and offending key) when the
    ``pins`` value is not a mapping, an entry is not a mapping, ``sha`` is
    missing or not a string, or ``resolved_at`` is missing or unparseable.
    """
    if not path.is_file():
        return Lockfile()

    yaml = YAML()
    raw = yaml.load(path)
    if raw is None:
        return Lockfile()
    if not isinstance(raw, Mapping):
        raise LockfileError(f"{path}: lockfile must be a mapping")

    pins_raw = raw.get("pins", {})
    if pins_raw is None:
        return Lockfile()
    if not isinstance(pins_raw, Mapping):
        raise LockfileError(f"{path}: 'pins' must be a mapping")

    pins: dict[str, PinEntry] = {}
    for uses, entry in pins_raw.items():
        if not isinstance(entry, Mapping):
            raise LockfileError(f"{path}: pin entry for {uses} must be a table")

        sha = entry.get("sha")
        if not isinstance(sha, str):
            raise LockfileError(f"{path}: pin {uses}: 'sha' must be a string")

        resolved_at = entry.get("resolved_at")
        if isinstance(resolved_at, datetime):
            resolved_dt = resolved_at
        elif isinstance(resolved_at, str):
            try:
                resolved_dt = datetime.fromisoformat(resolved_at)
            except ValueError as exc:
                raise LockfileError(
                    f"{path}: pin {uses}: invalid 'resolved_at' "
                    f"timestamp: {resolved_at!r}"
                ) from exc
        else:
            raise LockfileError(
                f"{path}: pin {uses}: 'resolved_at' must be a string or datetime"
            )

        pins[uses] = PinEntry(sha=sha, resolved_at=resolved_dt)
    return Lockfile(pins=pins)


def write_lockfile(lockfile: Lockfile, path: Path) -> None:
    """Write a lockfile to disk in sorted order."""
    pins_dict: dict[str, dict[str, str]] = {}
    for uses in sorted(lockfile.keys()):
        entry = lockfile.get(uses)
        assert entry is not None  # keys() guarantees presence
        pins_dict[uses] = {
            "sha": entry.sha,
            "resolved_at": DoubleQuotedScalarString(
                entry.resolved_at.astimezone(UTC).isoformat()
            ),
        }

    yaml = YAML()
    yaml.default_flow_style = False

    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("w") as fh:
        fh.write(_HEADER)
        yaml.dump({"pins": pins_dict}, fh)
